"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/lib/AuthContext";
import { feed as feedApi, votes as votesApi } from "@/lib/apiClient";

interface Post {
    id: string;
    content: string;
    category: string;
    post_type: string;
    author_anon_id: string;
    author_mood?: string;
    upvotes: number;
    downvotes: number;
    comment_count: number;
    is_own_post: boolean;
    user_vote: number;
    created_at: string;
}

const MOOD_EMOJI: Record<string, string> = {
    chill: "😌", excited: "🤩", stressed: "😰", happy: "😊", sad: "😔",
    curious: "🤔", tired: "😴", focused: "🎯", confused: "😵"
};

const CATEGORY_COLOR: Record<string, string> = {
    general: "bg-slate-100 text-slate-600",
    events: "bg-purple-100 text-purple-700",
    study: "bg-blue-100 text-blue-700",
    housing: "bg-amber-100 text-amber-700",
    food: "bg-orange-100 text-orange-700",
    sports: "bg-green-100 text-green-700",
};

export default function FeedPage() {
    const { user, isLoadingAuth, logout } = useAuth();
    const router = useRouter();
    const [posts, setPosts] = useState<Post[]>([]);
    const [loading, setLoading] = useState(true);
    const [sort, setSort] = useState("new");
    const [newContent, setNewContent] = useState("");
    const [posting, setPosting] = useState(false);

    // Auth guard
    useEffect(() => {
        if (isLoadingAuth) return;
        if (!user) { router.replace("/login"); return; }
        if (!user.school_verified) { router.replace("/onboarding/school"); return; }
        if (!user.age_verified) { router.replace("/onboarding/age"); return; }
    }, [user, isLoadingAuth, router]);

    const loadFeed = async () => {
        setLoading(true);
        try {
            const data = (await feedApi.list({ sort, limit: 20 })) as { posts: Post[] };
            setPosts(data.posts ?? []);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (user?.age_verified) loadFeed();
    }, [sort, user]);

    const handleVote = async (postId: string, value: 1 | -1 | 0) => {
        try {
            const res = (await votesApi.vote("post", postId, value)) as { upvotes: number; downvotes: number };
            setPosts((prev) =>
                prev.map((p) => p.id === postId ? { ...p, upvotes: res.upvotes, downvotes: res.downvotes, user_vote: value } : p)
            );
        } catch (e) { console.error(e); }
    };

    const handlePost = async () => {
        if (!newContent.trim()) return;
        setPosting(true);
        try {
            await feedApi.create({ content: newContent.trim(), category: "general" });
            setNewContent("");
            loadFeed();
        } catch (e) { console.error(e); }
        finally { setPosting(false); }
    };

    const timeAgo = (ts: string) => {
        const s = Math.floor((Date.now() - new Date(ts).getTime()) / 1000);
        if (s < 60) return "now";
        if (s < 3600) return `${Math.floor(s / 60)}m`;
        if (s < 86400) return `${Math.floor(s / 3600)}h`;
        return `${Math.floor(s / 86400)}d`;
    };

    if (isLoadingAuth || !user) return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center">
            <div className="w-6 h-6 border-2 border-slate-300 border-t-slate-700 rounded-full animate-spin" />
        </div>
    );

    return (
        <div className="min-h-screen bg-slate-50">
            {/* Top bar */}
            <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-100 shadow-sm">
                <div className="max-w-xl mx-auto px-4 py-3 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <span className="text-lg">🦇</span>
                        <span className="font-black text-slate-900 text-sm tracking-tight">Campus Echo</span>
                        {user.school_id && (
                            <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full font-medium">{user.school_id}</span>
                        )}
                    </div>
                    <div className="flex items-center gap-3">
                        <span className="text-xs text-slate-500 font-mono">@{user.handle}</span>
                        <button onClick={() => logout()} className="text-xs text-slate-400 hover:text-red-500 transition-colors">Sign out</button>
                    </div>
                </div>
            </div>

            <div className="max-w-xl mx-auto px-4 py-4 space-y-4">
                {/* Compose */}
                <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-4 space-y-3">
                    <div className="flex items-start gap-3">
                        <div className="w-8 h-8 rounded-xl bg-blue-50 flex items-center justify-center text-base shrink-0">
                            {MOOD_EMOJI[user.mood ?? "chill"] ?? "😌"}
                        </div>
                        <textarea
                            value={newContent}
                            onChange={(e) => setNewContent(e.target.value)}
                            placeholder="What's on your mind?"
                            rows={3}
                            className="flex-1 text-sm text-slate-800 placeholder-slate-400 resize-none focus:outline-none"
                        />
                    </div>
                    <div className="flex justify-end">
                        <button
                            onClick={handlePost}
                            disabled={!newContent.trim() || posting}
                            className="bg-blue-500 hover:bg-blue-400 disabled:opacity-40 text-white text-xs font-bold px-4 py-2 rounded-xl transition-all active:scale-95 shadow-sm"
                        >
                            {posting ? "Posting…" : "Post"}
                        </button>
                    </div>
                </div>

                {/* Sort tabs */}
                <div className="flex bg-white border border-slate-100 shadow-sm p-1 rounded-xl">
                    {["new", "hot", "top"].map((s) => (
                        <button
                            key={s}
                            onClick={() => setSort(s)}
                            className={`flex-1 py-1.5 text-xs font-semibold rounded-lg transition-all ${sort === s ? "bg-slate-900 text-white shadow" : "text-slate-500 hover:text-slate-900"
                                }`}
                        >
                            {s.charAt(0).toUpperCase() + s.slice(1)}
                        </button>
                    ))}
                </div>

                {/* Posts */}
                {loading ? (
                    Array(4).fill(0).map((_, i) => (
                        <div key={i} className="bg-white rounded-2xl border border-slate-100 p-4 animate-pulse space-y-3">
                            <div className="h-3 bg-slate-100 rounded w-3/4" />
                            <div className="h-3 bg-slate-100 rounded w-1/2" />
                        </div>
                    ))
                ) : posts.length === 0 ? (
                    <div className="text-center py-20 bg-white rounded-2xl border border-slate-100">
                        <div className="text-4xl mb-3">👻</div>
                        <p className="text-slate-500 font-medium text-sm">No posts yet. Be the first!</p>
                    </div>
                ) : (
                    posts.map((post) => (
                        <div key={post.id} className="bg-white rounded-2xl border border-slate-100 shadow-sm p-4 space-y-3">
                            {/* Post header */}
                            <div className="flex items-center gap-2">
                                <div className="w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center text-sm">
                                    {MOOD_EMOJI[post.author_mood ?? "chill"] ?? "😌"}
                                </div>
                                <div>
                                    <p className="text-xs font-semibold text-slate-700">{post.is_own_post ? "You" : `@${post.author_anon_id.substring(0, 8)}`}</p>
                                    <p className="text-xs text-slate-400">{timeAgo(post.created_at)}</p>
                                </div>
                                {post.category !== "general" && (
                                    <span className={`ml-auto text-xs px-2 py-0.5 rounded-full font-medium ${CATEGORY_COLOR[post.category] ?? CATEGORY_COLOR.general}`}>
                                        {post.category}
                                    </span>
                                )}
                            </div>

                            {/* Content */}
                            <p className="text-sm text-slate-800 leading-relaxed">{post.content}</p>

                            {/* Actions */}
                            <div className="flex items-center gap-4 pt-1">
                                <div className="flex items-center gap-1">
                                    <button
                                        onClick={() => handleVote(post.id, post.user_vote === 1 ? 0 : 1)}
                                        className={`w-7 h-7 rounded-lg flex items-center justify-center text-sm transition-all active:scale-90 ${post.user_vote === 1 ? "bg-blue-50 text-blue-600" : "text-slate-400 hover:text-blue-600 hover:bg-blue-50"
                                            }`}
                                    >↑</button>
                                    <span className="text-xs font-semibold text-slate-700 min-w-[1.5rem] text-center">
                                        {post.upvotes - post.downvotes}
                                    </span>
                                    <button
                                        onClick={() => handleVote(post.id, post.user_vote === -1 ? 0 : -1)}
                                        className={`w-7 h-7 rounded-lg flex items-center justify-center text-sm transition-all active:scale-90 ${post.user_vote === -1 ? "bg-red-50 text-red-500" : "text-slate-400 hover:text-red-500 hover:bg-red-50"
                                            }`}
                                    >↓</button>
                                </div>
                                <button className="flex items-center gap-1 text-slate-400 hover:text-slate-600 transition-colors">
                                    <span className="text-sm">💬</span>
                                    <span className="text-xs font-medium">{post.comment_count}</span>
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}
